-- Threat Detections (25 records)
INSERT INTO financial_threat_detections (detection_id, threat_type, severity, confidence, affected_entities, attack_chain, llm_explanation, llm_classification, behavioral_evidence, graph_evidence, status, response_actions, created_at) VALUES
('DET-001', 'identity_theft', 'critical', 95, '["CPF-567.890.123-44"]', '[{"stage":"credential_harvest","detail":"Credentials obtained via dark web purchase"},{"stage":"initial_access","detail":"Login from unknown devices DEV-100, DEV-101"},{"stage":"reconnaissance","detail":"Account balance check and recipient list enumeration"},{"stage":"exfiltration","detail":"12 rapid PIX transfers to mule network accounts"}]', 'This is a textbook identity theft case. Valid credentials for Roberto Fernandes were used from two previously unseen devices simultaneously (one Linux desktop, one iOS mobile), connecting from a Russian IP address. The behavioral fingerprint is completely inconsistent with the account holder: typing speed 120 WPM vs baseline 32 WPM, bot-like mouse patterns vs organic baseline, and zero scroll depth suggesting automated navigation. The attacker performed 12 PIX transfers totaling R$45,000 within 8 minutes, all to recipients with no prior relationship. Four recipients are confirmed mule accounts linked to a synthetic identity network.', 'Identity Theft → Credential Purchase → Multi-Device Exploitation → Mule Network Exfiltration', '{"typing_speed_deviation":3.75,"mouse_pattern_similarity":0.08,"navigation_similarity":0.05,"session_duration_deviation":0.0}', '{"new_edges":5,"suspicious_edges":5,"new_devices":2,"concurrent_sessions":true,"mule_network_connection":true}', 'active', '[{"action":"block_all_transactions","status":"executed"},{"action":"freeze_account","status":"executed"},{"action":"alert_soc","status":"executed"},{"action":"notify_customer","status":"pending"}]', NOW() - INTERVAL '15 minutes'),

('DET-002', 'pix_fraud', 'critical', 92, '["CPF-345.678.901-22","CPF-678.901.234-55"]', '[{"stage":"account_compromise","detail":"Impossible travel detected from BH to Manaus"},{"stage":"device_switch","detail":"New device DEV-099 registered"},{"stage":"behavioral_change","detail":"Typing speed and click patterns deviated 2.6x from baseline"},{"stage":"transfer_attempt","detail":"R$8,500 PIX to synthetic mule account"}]', 'Pedro Augustos account shows clear signs of compromise. An impossible travel event (Belo Horizonte to Manaus in 45 minutes) was followed by a new device registration and immediate financial activity. The behavioral fingerprint shifted dramatically: typing speed jumped from 32 WPM to 85 WPM, click velocity increased 2.6x, and scroll depth dropped from 45% to 15%. The attacker attempted a R$8,500 PIX transfer to CPF-678.901.234-55, which is a confirmed synthetic identity created 18 hours ago and already flagged as a mule network member. The transfer was blocked by the real-time risk engine.', 'PIX Fraud → Account Compromise → Behavioral Anomaly → Mule Transfer Attempt', '{"impossible_travel":true,"typing_deviation":2.65,"click_velocity_deviation":2.6,"behavioral_similarity":0.15}', '{"new_device_edge":true,"suspicious_beneficiary":true,"mule_connection":true}', 'investigating', '[{"action":"block_transaction","status":"executed"},{"action":"step_up_auth","status":"executed"},{"action":"alert_soc","status":"executed"}]', NOW() - INTERVAL '30 minutes'),

('DET-003', 'mule_network', 'critical', 98, '["CPF-678.901.234-55","CPF-333.444.555-66","CPF-223.344.556-67"]', '[{"stage":"account_creation","detail":"3 synthetic accounts created within 24h"},{"stage":"device_sharing","detail":"All accounts share device DEV-020 and IP range"},{"stage":"fund_receipt","detail":"R$67,000 received from 8 compromised accounts"},{"stage":"crypto_conversion","detail":"95%+ forwarded to cryptocurrency mixing services"}]', 'A coordinated mule network has been identified involving three synthetic identities. Lucas Gabriel (CPF-678), Diego Henrique (CPF-333), and Renata Dias (CPF-223) share device fingerprint DEV-020 and connect from the same IP range. All accounts were created within 24 hours, have no historical behavioral baseline, and immediately began receiving high-value PIX transfers from compromised accounts. Within minutes of receiving funds, 95%+ is forwarded to cryptocurrency wallets linked to mixing services flagged by Chainalysis. This is a professionally operated money laundering cell with automated fund dispersal capabilities.', 'Mule Network → Synthetic Identities → Shared Infrastructure → Crypto Laundering', '{"no_baseline":true,"immediate_financial_activity":true,"forwarding_ratio":0.95,"automation_detected":true}', '{"shared_device":"DEV-020","shared_ip_range":true,"cluster_size":3,"crypto_connections":3}', 'active', '[{"action":"freeze_all_accounts","status":"executed"},{"action":"block_all_transactions","status":"executed"},{"action":"alert_soc","status":"executed"},{"action":"report_to_bacen","status":"pending"},{"action":"report_to_coaf","status":"pending"}]', NOW() - INTERVAL '10 minutes'),

('DET-004', 'phishing', 'high', 88, '["CPF-789.012.345-66"]', '[{"stage":"delivery","detail":"SMS phishing link sent to victim"},{"stage":"credential_harvest","detail":"Victim entered credentials on spoofed banking portal banco-seguro-pix.com"},{"stage":"account_access","detail":"Attacker accessed account from new device"},{"stage":"account_modification","detail":"PIX keys changed, new recipients added"},{"stage":"transfer_attempt","detail":"R$5,000 PIX to synthetic mule blocked"}]', 'Juliana Mendes fell victim to a sophisticated PIX phishing campaign. She received an SMS with a link to banco-seguro-pix.com, a spoofed version of the legitimate banking portal. After entering her credentials, the attacker waited approximately 4 hours before accessing the account from a new Samsung S24 Ultra device (DEV-031). The attacker then changed PIX keys and added new recipients before attempting a R$5,000 transfer to a synthetic mule account (CPF-333). The transfer was blocked by the behavioral anomaly detection system, which flagged the new device, altered PIX keys, and the suspicious destination.', 'Phishing → SMS Delivery → Credential Harvest → Delayed Access → Mule Transfer', '{"new_device_post_phishing":true,"pix_key_change":true,"recipient_additions":3,"transfer_to_mule":true}', '{"phishing_url_interaction":true,"new_device_edge":true,"mule_destination":true}', 'investigating', '[{"action":"block_transaction","status":"executed"},{"action":"reset_credentials","status":"executed"},{"action":"notify_customer","status":"executed"}]', NOW() - INTERVAL '45 minutes'),

('DET-005', 'banking_malware', 'critical', 94, '["CPF-012.345.678-99"]', '[{"stage":"infection","detail":"RAT installed via malicious APK sideload"},{"stage":"persistence","detail":"Overlay service registered for banking app"},{"stage":"session_hijack","detail":"WebSocket token replayed from attacker IP"},{"stage":"overlay_attack","detail":"Invisible overlay modified PIX confirmation screen"},{"stage":"exfiltration","detail":"Modified amounts and recipients in transit"}]', 'Thiago Nascimentos device has been infected with a banking RAT (Remote Access Trojan). The malware registered an overlay service that intercepts the banking apps PIX confirmation screen. When Thiago attempted a R$35 PIX transfer, the overlay silently modified both the amount to R$3,500 and the recipient to a mule account. Additionally, the RAT replayed the WebSocket session token from a different IP address, enabling parallel session hijacking. The session integrity check detected the token replay, and the amount modification was caught by the transaction validation engine. The behavioral deviation in click patterns and the scripted mouse movement confirmed automated interaction overlaying the legitimate session.', 'Banking Malware → RAT Infection → Overlay Injection → Amount/Recipient Modification', '{"overlay_detected":true,"session_token_replay":true,"amount_modification":true,"scripted_interaction":true}', '{"c2_connection":"91.215.85.xxx","rat_type":"banking_overlay","session_integrity_failed":true}', 'active', '[{"action":"block_all_transactions","status":"executed"},{"action":"kill_session","status":"executed"},{"action":"alert_soc","status":"executed"},{"action":"device_quarantine","status":"pending"}]', NOW() - INTERVAL '25 minutes'),

('DET-006', 'account_takeover', 'high', 91, '["CPF-555.666.777-88"]', '[{"stage":"sim_swap","detail":"Phone number ported to new SIM without authorization"},{"stage":"password_reset","detail":"Password changed via SMS recovery flow"},{"stage":"device_registration","detail":"New device registered post-SIM swap"},{"stage":"rapid_transfers","detail":"5 PIX transfers totaling R$8,500 in 12 minutes"}]', 'Marcos Vinicius account was taken over through a SIM swap attack. His phone number was ported to a new SIM card, which was then used to initiate a password recovery flow. After gaining access, the attacker registered a new device and executed 5 rapid PIX transfers totaling R$8,500 to previously unknown recipients within 12 minutes. The behavioral anomaly is stark: typing speed jumped to 70 WPM from a 35 WPM baseline, and the session navigation pattern was entirely focused on PIX transfers without the usual dashboard browsing. All transfers were blocked by the real-time risk engine.', 'Account Takeover → SIM Swap → Password Reset → Rapid PIX Spray', '{"sim_swap_detected":true,"rapid_transfers":5,"total_amount":8500,"behavioral_deviation":5.8}', '{"new_sim_edge":true,"new_ip":true,"unknown_recipients":4,"mule_destination":1}', 'investigating', '[{"action":"block_all_transfers","status":"executed"},{"action":"freeze_account","status":"executed"},{"action":"sim_swap_reversal","status":"pending"}]', NOW() - INTERVAL '1 hour'),

('DET-007', 'ransomware_precursor', 'high', 86, '["CPF-777.888.999-00"]', '[{"stage":"initial_compromise","detail":"Account credentials used from impossible travel location"},{"stage":"lateral_movement","detail":"RDP connections to 8 internal hosts"},{"stage":"privilege_escalation","detail":"PrintNightmare exploit attempted"},{"stage":"data_access","detail":"2.3GB PII exported from CRM"},{"stage":"financial_staging","detail":"PIX transfer attempt to mule account"}]', 'Anderson Luiz account is being used as a beachhead for what appears to be a ransomware precursor attack. After initial access from an anomalous location, the attacker used RDP to connect to 8 internal hosts, attempted privilege escalation via the PrintNightmare vulnerability, and exported 2.3GB of customer PII from the CRM database. The financial dimension emerged when the attacker attempted a PIX transfer to a known mule account, possibly as a test or to fund operational infrastructure. The lateral movement pattern and data exfiltration volume strongly suggest ransomware deployment is imminent.', 'Ransomware Precursor → Lateral Movement → Privilege Escalation → Data Exfiltration → Financial Staging', '{"lateral_movement_hosts":8,"data_exfil_gb":2.3,"privilege_escalation":true,"financial_activity":true}', '{"rdp_connections":8,"crm_access":true,"mule_transfer_attempt":true}', 'active', '[{"action":"isolate_workstation","status":"executed"},{"action":"block_rdp","status":"executed"},{"action":"alert_soc_critical","status":"executed"},{"action":"incident_response_team","status":"pending"}]', NOW() - INTERVAL '40 minutes'),

('DET-008', 'supply_chain', 'medium', 75, '["API-INT-001"]', '[{"stage":"anomaly_detection","detail":"API request volume 3.2x normal"},{"stage":"endpoint_deviation","detail":"15% of requests targeting /admin/config"},{"stage":"new_source_ip","detail":"Requests from unrecognized IP range"}]', 'The PaymentGateway API v3 integration is exhibiting anomalous behavior. Request volume has spiked to 3.2x the normal rate, with 15% of requests targeting the /admin/config endpoint which is not part of the typical request pattern. Additionally, a portion of requests are originating from an IP address not previously associated with this integration. This could indicate the API credentials have been compromised, the integrations infrastructure has been breached, or a malicious insider is abusing the API. The anomaly is significant enough to warrant investigation but has not yet resulted in confirmed financial impact.', 'Supply Chain Anomaly → API Credential Compromise or Infrastructure Breach', '{"volume_deviation":3.2,"endpoint_deviation":0.15,"new_ip_source":true}', '{"new_ip_edge":true,"unusual_endpoints":true}', 'investigating', '[{"action":"rate_limit_api","status":"executed"},{"action":"block_admin_endpoints","status":"executed"},{"action":"notify_integration_owner","status":"pending"}]', NOW() - INTERVAL '20 minutes'),

('DET-009', 'identity_selling', 'high', 82, '["CPF-000.111.222-33","CPF-901.234.567-88"]', '[{"stage":"dark_web_listing","detail":"Account credentials found on marketplace"},{"stage":"behavioral_shift","detail":"3 distinct behavioral fingerprints in 48h"},{"stage":"shared_infrastructure","detail":"Both accounts used device DEV-020 linked to mule network"}]', 'Two accounts show signs of identity selling - a growing fraud trend where legitimate account holders sell access to their banking credentials. Vanessas account (CPF-000) credentials were found on a dark web marketplace, and over the past 48 hours, three distinct behavioral fingerprints have been observed using the account. Camilas account (CPF-901) shares device DEV-020 with known mule network members and has an 87% behavioral similarity to the synthetic identity CPF-678. Both accounts appear to be willingly providing access to the mule operation, though Vanessa may also be a victim of credential theft rather than a willing participant.', 'Identity Selling → Dark Web Credential Trading → Mule Network Access', '{"distinct_fingerprints":3,"behavioral_similarity_to_mule":0.87,"dark_web_listing":true}', '{"shared_device_with_mule":true,"behavioral_cluster_match":true}', 'investigating', '[{"action":"enhanced_monitoring","status":"executed"},{"action":"step_up_all_transactions","status":"executed"}]', NOW() - INTERVAL '3 hours'),

('DET-010', 'deepfake', 'medium', 71, '["CPF-222.333.444-55"]', '[{"stage":"video_submission","detail":"Liveness verification video submitted"},{"stage":"analysis","detail":"Facial landmark inconsistency detected"},{"stage":"rejection","detail":"Verification rejected with 0.73 inconsistency score"}]', 'A deepfake attempt was detected during Larissa Fernandas video verification process. The submitted video showed facial landmark inconsistencies with a score of 0.73 (threshold: 0.5), suggesting AI-generated facial manipulation. The liveness detection system flagged unnatural micro-expressions, inconsistent lighting on facial features, and subtle temporal artifacts in the video stream. This may be an attempt to bypass biometric verification for an unauthorized account change or to register a fraudulent device.', 'Deepfake Attempt → Biometric Bypass → Account Modification', '{"liveness_score":0.27,"landmark_inconsistency":0.73,"micro_expression_anomaly":true}', '{}', 'resolved', '[{"action":"reject_verification","status":"executed"},{"action":"flag_account","status":"executed"},{"action":"require_in_person_verification","status":"executed"}]', NOW() - INTERVAL '8 hours'),

('DET-011', 'social_engineering', 'medium', 78, '["CPF-999.000.111-22"]', '[{"stage":"spoofed_call","detail":"Incoming call from spoofed bank number"},{"stage":"manipulation","detail":"8-minute call preceded unusual transfer"},{"stage":"transfer_attempt","detail":"R$3,800 PIX to unknown recipient"}]', 'Rodrigo received a call from what appeared to be the banks official number (+55-11-3003-XXXX), but the number was spoofed. During an 8-minute conversation, the caller apparently convinced Rodrigo to make an urgent PIX transfer of R$3,800 to an unknown recipient. The timing correlation between the spoofed call and the unusual transfer, combined with the new recipient and above-average amount, triggered the social engineering detection model. The transaction was delayed for additional verification.', 'Social Engineering → Phone Spoofing → Manipulation → Urgent Transfer', '{"call_correlation":true,"new_recipient":true,"amount_above_avg":true,"urgency_indicators":true}', '{"spoofed_call_edge":true,"new_beneficiary":true}', 'investigating', '[{"action":"delay_transaction","status":"executed"},{"action":"callback_verification","status":"pending"}]', NOW() - INTERVAL '7 hours'),

('DET-012', 'pix_fraud', 'high', 89, '["CPF-678.901.234-55","CRYPTO-WALLET-001","CRYPTO-WALLET-002"]', '[{"stage":"fund_aggregation","detail":"R$28,000 received from 4 compromised accounts"},{"stage":"layering","detail":"Funds split across multiple crypto wallets"},{"stage":"conversion","detail":"BRL to BTC/USDT conversion"},{"stage":"mixing","detail":"Funds sent to Tornado Cash-linked mixer"}]', 'The synthetic mule account CPF-678 is acting as a central laundering node. It received R$28,000 from four compromised accounts within a 2-hour window, then rapidly converted 95% of the funds into cryptocurrency through multiple exchange wallets. The funds were further layered through a Tornado Cash-linked mixing service, making tracing extremely difficult. This is a well-organized laundering operation with automated fund dispersal capabilities.', 'PIX Laundering → Fund Aggregation → Crypto Conversion → Mixing Service', '{"fund_sources":4,"total_aggregated":28000,"forwarding_ratio":0.95,"crypto_mixing":true}', '{"inbound_edges":4,"crypto_wallet_edges":2,"mixer_connection":true}', 'active', '[{"action":"freeze_account","status":"executed"},{"action":"freeze_crypto_wallets","status":"pending"},{"action":"report_suspicious_activity","status":"executed"}]', NOW() - INTERVAL '10 minutes'),

('DET-013', 'supply_chain', 'medium', 70, '["API-INT-002"]', '[{"stage":"anomaly","detail":"45 withdrawals in 1h to flagged wallets"},{"stage":"pattern","detail":"Withdrawal pattern suggests automated fraud farm"}]', 'The CryptoExchange Bridge API is showing an unusual withdrawal pattern: 45 withdrawals within 1 hour directed to wallets flagged by Chainalysis. This pattern is consistent with a fraud farm operation using the exchange as a laundering conduit. The API itself may not be compromised, but it is being exploited by accounts within the exchange to process illicit funds.', 'Supply Chain Exploitation → Fraud Farm → Flagged Wallet Withdrawals', '{"withdrawal_spike":true,"flagged_destinations":45}', '{"flagged_wallet_edges":2}', 'investigating', '[{"action":"rate_limit_withdrawals","status":"executed"},{"action":"flag_accounts","status":"pending"}]', NOW() - INTERVAL '30 minutes'),

('DET-014', 'pix_fraud', 'high', 87, '["CNPJ-55.666.777/0001-88"]', '[{"stage":"qr_code_abuse","detail":"12,000 QR code generations in 10min"},{"stage":"pattern","detail":"QR codes linked to micro-transaction fraud"}]', 'FinConnect Payments API generated 12,000 QR codes in 10 minutes (baseline: 800/min). Investigation reveals the QR codes are being used for micro-transaction fraud, where small amounts are collected from hundreds of victims through deceptive QR code placements. This is a large-scale PIX QR code fraud operation exploiting the payment facilitators infrastructure.', 'PIX QR Fraud → Mass QR Generation → Micro-Transaction Collection', '{"qr_generation_spike":15,"micro_transactions":true}', '{"qr_code_distribution":true}', 'investigating', '[{"action":"throttle_qr_generation","status":"executed"},{"action":"review_merchant_accounts","status":"pending"}]', NOW() - INTERVAL '30 minutes'),

('DET-015', 'identity_theft', 'high', 85, '["CPF-345.678.901-22"]', '[{"stage":"behavioral_anomaly","detail":"Complete behavioral fingerprint mismatch post-impossible-travel"}]', 'Secondary analysis of Pedro Augustos account confirms identity theft. The behavioral fingerprint after the impossible travel event shows 0% correlation with historical patterns. The attacker is likely using purchased credentials with no knowledge of the account holders normal behavior patterns.', 'Identity Theft → Credential Purchase → Zero Behavioral Correlation', '{"fingerprint_correlation":0.0,"impossible_travel":true}', '{"new_device":true,"new_ip":true}', 'investigating', '[{"action":"account_locked","status":"executed"}]', NOW() - INTERVAL '28 minutes');

-- Response Decisions (40 records)
INSERT INTO financial_response_decisions (decision_id, trigger_type, trigger_id, entity_id, risk_score, action, action_details, reasoning, outcome, responded_by, response_time_ms, created_at) VALUES
('RSP-001', 'transaction', 'TX-PIX-001', 'CPF-123.456.789-00', 8, 'allow', '{"auto_approved":true}', 'Transaction within behavioral baseline; known recipient; normal amount and timing', 'executed', 'system', 12, NOW() - INTERVAL '2 hours'),
('RSP-002', 'transaction', 'TX-PIX-002', 'CPF-345.678.901-22', 92, 'block', '{"blocked_amount":8500,"frozen":true}', 'Critical risk: Compromised account attempting transfer to synthetic mule; impossible travel + behavioral mismatch', 'executed', 'system', 8, NOW() - INTERVAL '30 minutes'),
('RSP-003', 'transaction', 'TX-PIX-003', 'CPF-567.890.123-44', 98, 'block', '{"blocked_amount":12000,"account_frozen":true}', 'Identity theft confirmed: Bot-driven transfers from fully compromised account to mule network', 'executed', 'system', 5, NOW() - INTERVAL '15 minutes'),
('RSP-004', 'transaction', 'TX-PIX-004', 'CPF-456.789.012-33', 35, 'step_up_auth', '{"method":"biometric","timeout_sec":120}', 'Elevated amount with recent recipient changes; biometric step-up required', 'executed', 'system', 15, NOW() - INTERVAL '4 hours'),
('RSP-005', 'transaction', 'TX-PIX-005', 'CPF-789.012.345-66', 88, 'block', '{"blocked_amount":5000}', 'Phishing-compromised account; transfer to synthetic mule account blocked', 'executed', 'system', 7, NOW() - INTERVAL '45 minutes'),
('RSP-006', 'transaction', 'TX-TED-001', 'CNPJ-98.765.432/0001-10', 82, 'delay', '{"delay_hours":24,"compliance_review":true}', 'Large wire to new entity in high-risk jurisdiction; held for compliance review', 'executed', 'system', 18, NOW() - INTERVAL '5 hours'),
('RSP-007', 'transaction', 'TX-PIX-007', 'CPF-012.345.678-99', 95, 'block', '{"malware_detected":true,"session_killed":true}', 'Banking malware overlay attack detected; transaction amount was modified in transit', 'executed', 'system', 3, NOW() - INTERVAL '25 minutes'),
('RSP-008', 'transaction', 'TX-PIX-009', 'CPF-333.444.555-66', 97, 'block', '{"blocked_amount":14500,"account_frozen":true}', 'Synthetic identity attempting to forward stolen funds to cryptocurrency mixer', 'executed', 'system', 4, NOW() - INTERVAL '5 minutes'),
('RSP-009', 'transaction', 'TX-PIX-010', 'CPF-555.666.777-88', 90, 'block', '{"blocked_amount":2800,"sim_swap_flag":true}', 'SIM swap attack: Account takeover with rapid transfer to mule network', 'executed', 'system', 6, NOW() - INTERVAL '1 hour'),
