-- Threat Simulations (8 Monte Carlo simulations)
INSERT INTO financial_threat_simulations (simulation_id, scenario_name, scenario_type, parameters, results, attack_paths, detection_gaps, suggested_rules, confidence_interval, iterations, status, created_at) VALUES
('SIM-001', 'PIX Mule Network Expansion', 'mule_network', '{"initial_mules":3,"growth_rate":0.4,"compromised_accounts":10,"avg_transfer":5000,"simulation_days":30}', '{"total_laundered":1850000,"detection_rate":0.87,"avg_time_to_detect_hours":2.4,"false_positive_rate":0.03,"accounts_frozen":28,"crypto_converted":0.65}', '[{"path":"compromise→mule_creation→fund_transfer→crypto_conversion→mixing","probability":0.45,"avg_amount":12000},{"path":"phishing→credential_harvest→ato→mule_transfer","probability":0.3,"avg_amount":8000},{"path":"sim_swap→ato→spray_transfer→mule_aggregation","probability":0.25,"avg_amount":6000}]', '[{"gap":"Detection delay for micro-transactions under R$200","impact":"high","description":"Current thresholds miss micro-layering through 50+ small transfers"},{"gap":"Cross-institution mule detection","impact":"medium","description":"Mule accounts at other institutions are invisible to our graph"}]', '[{"rule":"Micro-transaction velocity alert: >20 transactions <R$200 in 1h","confidence":0.82},{"rule":"Shared device fingerprint across >2 new accounts in 24h","confidence":0.91}]', 0.95, 10000, 'completed', NOW() - INTERVAL '2 hours'),

('SIM-002', 'Coordinated Phishing Campaign', 'pix_fraud', '{"campaign_size":5000,"click_rate":0.08,"credential_harvest_rate":0.6,"ato_success_rate":0.4,"avg_steal_amount":3500}', '{"total_attempted_theft":560000,"total_prevented":487200,"prevention_rate":0.87,"victims_compromised":160,"avg_response_time_sec":45,"false_negatives":21}', '[{"path":"sms_phishing→spoofed_portal→credential_harvest→delayed_ato→pix_transfer","probability":0.55,"avg_delay_hours":4},{"path":"email_phishing→malicious_link→session_hijack→immediate_transfer","probability":0.3,"avg_delay_hours":0.5},{"path":"voice_phishing→social_engineering→guided_transfer","probability":0.15,"avg_amount":5000}]', '[{"gap":"SMS phishing link detection latency","impact":"high","description":"Average 6h before phishing URLs are blocklisted; 40% of clicks occur in first 2h"},{"gap":"Voice phishing correlation","impact":"medium","description":"No automated correlation between incoming calls and subsequent unusual transfers"}]', '[{"rule":"Post-credential-change transfer delay: 24h cooling period for new recipients after password/PIX key change","confidence":0.88},{"rule":"Call-transfer correlation: Flag transfers within 30min of calls from high-risk number patterns","confidence":0.75}]', 0.95, 10000, 'completed', NOW() - INTERVAL '4 hours'),

('SIM-003', 'Banking Malware Outbreak', 'banking_malware', '{"infection_vector":"sideloaded_apk","target_devices":1000,"infection_rate":0.12,"overlay_success_rate":0.7,"avg_modified_amount":3000}', '{"total_attempted_theft":252000,"total_prevented":226800,"prevention_rate":0.9,"devices_infected":120,"overlays_detected":84,"avg_detection_time_sec":15}', '[{"path":"malicious_apk→rat_install→overlay_register→pix_intercept→amount_modify","probability":0.6},{"path":"drive_by_download→rat_install→session_clone→parallel_session","probability":0.25},{"path":"supply_chain_sdk→embedded_rat→delayed_activation→mass_overlay","probability":0.15}]', '[{"gap":"Pre-infection detection","impact":"high","description":"No visibility into device health before banking app launch; infections detected only at transaction time"},{"gap":"SDK supply chain monitoring","impact":"critical","description":"Third-party SDKs in mobile app not monitored for embedded RATs"}]', '[{"rule":"Session integrity hash: Real-time hash comparison of client-side UI state vs server expectations","confidence":0.92},{"rule":"Device attestation: Require SafetyNet/Play Integrity before high-value transactions","confidence":0.85}]', 0.95, 10000, 'completed', NOW() - INTERVAL '6 hours'),

('SIM-004', 'Synthetic Identity Factory', 'identity_theft', '{"synthetic_accounts_created":50,"verification_bypass_rate":0.3,"avg_account_lifetime_days":5,"avg_laundered_per_account":15000}', '{"total_laundered":225000,"detection_rate":0.82,"avg_detection_time_hours":8,"accounts_caught_pre_transaction":9,"accounts_caught_during_transaction":32,"accounts_undetected":9}', '[{"path":"stolen_cpf→synthetic_account→immediate_pix_activity→crypto_exit","probability":0.5},{"path":"fabricated_identity→slow_build→legitimate_transactions→sudden_pivot→laundering","probability":0.3},{"path":"identity_farm→bulk_creation→distributed_micro_laundering","probability":0.2}]', '[{"gap":"Onboarding velocity detection","impact":"high","description":"Accounts completing full onboarding in <60 seconds not flagged"},{"gap":"CPF cross-reference latency","impact":"medium","description":"Receita Federal validation takes 4-6h; account is active before validation completes"}]', '[{"rule":"Onboarding speed threshold: Flag accounts completing registration in <2 minutes","confidence":0.89},{"rule":"First-transaction behavioral baseline: Require 72h activity before enabling transfers >R$500","confidence":0.78}]', 0.95, 10000, 'completed', NOW() - INTERVAL '8 hours'),

('SIM-005', 'Ransomware Financial Impact', 'ransomware', '{"entry_points":5,"lateral_movement_speed":"fast","encryption_targets":["crm","financial_db","backup"],"ransom_demand_btc":15,"financial_theft_parallel":true}', '{"estimated_downtime_hours":72,"estimated_financial_loss":4500000,"data_at_risk_gb":450,"accounts_potentially_exposed":125000,"lateral_movement_detected":true,"avg_detection_time_min":18}', '[{"path":"phished_employee→rdp_pivot→domain_admin→mass_encryption","probability":0.4},{"path":"vpn_exploit→foothold→mimikatz→lateral→encryption","probability":0.35},{"path":"supply_chain_compromise→trusted_access→immediate_encryption","probability":0.25}]', '[{"gap":"RDP lateral movement correlation with financial accounts","impact":"critical","description":"No automated link between network lateral movement and financial account compromise"},{"gap":"Backup integrity monitoring","impact":"high","description":"Backup encryption/deletion not correlated with financial system alerts"}]', '[{"rule":"RDP-to-financial correlation: Alert when accounts involved in RDP lateral movement attempt financial transactions","confidence":0.93},{"rule":"Data exfiltration threshold: Block all transactions when >500MB exported from financial databases","confidence":0.88}]', 0.95, 10000, 'completed', NOW() - INTERVAL '12 hours'),

('SIM-006', 'Supply Chain API Compromise', 'supply_chain', '{"compromised_apis":2,"attack_duration_days":14,"data_exfiltration":true,"transaction_manipulation":true}', '{"transactions_manipulated":340,"total_financial_impact":890000,"detection_time_days":3,"false_transactions_created":85,"api_keys_rotated":6}', '[{"path":"api_key_theft→gradual_volume_increase→transaction_injection","probability":0.45},{"path":"sdk_compromise→embedded_exfiltration→slow_drain","probability":0.35},{"path":"insider_threat→api_abuse→bulk_manipulation","probability":0.2}]', '[{"gap":"Gradual volume increase detection","impact":"high","description":"Slow 10% daily volume increases go undetected for up to 7 days"},{"gap":"Transaction integrity verification","impact":"critical","description":"No end-to-end hash verification for API-initiated transactions"}]', '[{"rule":"API behavioral drift: Alert on >15% deviation from 7-day rolling average","confidence":0.84},{"rule":"Transaction integrity hash: Require cryptographic proof for all API-initiated transfers","confidence":0.95}]', 0.95, 10000, 'completed', NOW() - INTERVAL '1 day'),

('SIM-007', 'Mass SIM Swap Campaign', 'account_takeover', '{"targets":200,"sim_swap_success_rate":0.35,"avg_time_to_drain_min":15,"avg_amount_per_victim":5000}', '{"total_attempted_theft":350000,"total_prevented":301000,"prevention_rate":0.86,"successful_drains":28,"avg_detection_time_min":8,"carrier_notification_time_min":45}', '[{"path":"social_engineering_carrier→sim_port→password_reset→rapid_drain","probability":0.6},{"path":"insider_at_carrier→bulk_sim_swap→coordinated_drain","probability":0.25},{"path":"ss7_exploit→sms_intercept→otp_capture→ato","probability":0.15}]', '[{"gap":"Carrier notification delay","impact":"critical","description":"Average 45min before carrier confirms SIM swap; most damage occurs in first 15min"},{"gap":"SMS-based 2FA dependency","impact":"high","description":"35% of accounts still rely solely on SMS OTP for 2FA"}]', '[{"rule":"SIM change + password reset correlation: Immediate account lock when both events occur within 1h","confidence":0.94},{"rule":"Migrate to app-based 2FA: Enforce TOTP for accounts >R$10,000 balance","confidence":0.88}]', 0.95, 10000, 'completed', NOW() - INTERVAL '18 hours'),

('SIM-008', 'Deepfake Biometric Bypass', 'identity_theft', '{"deepfake_quality":"high","target_verifications":100,"bypass_rate":0.15,"post_bypass_actions":["account_change","device_add","transfer"]}', '{"bypass_attempts":100,"successful_bypasses":15,"detected_deepfakes":78,"inconclusive":7,"avg_detection_confidence":0.82,"post_bypass_damage":45000}', '[{"path":"social_media_scrape→deepfake_generation→liveness_bypass→account_takeover","probability":0.5},{"path":"stolen_id_document→face_swap→verification_bypass→device_registration","probability":0.35},{"path":"real_time_deepfake→video_call_bypass→authorized_changes","probability":0.15}]', '[{"gap":"Real-time video deepfake detection","impact":"critical","description":"Current liveness checks optimized for pre-recorded videos; real-time face swap during video calls detected only 40% of the time"},{"gap":"Multi-modal verification","impact":"high","description":"Single-factor biometric verification insufficient against high-quality deepfakes"}]', '[{"rule":"Multi-challenge liveness: Random head movement + spoken phrase + lighting variation in single verification","confidence":0.87},{"rule":"Behavioral+biometric fusion: Require both biometric match AND behavioral consistency for high-risk actions","confidence":0.91}]', 0.95, 10000, 'completed', NOW() - INTERVAL '1 day');
